var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FIREWORK"},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"결국...... 운명의 상대 같은 건...... 없던 거였나?","JPN":"結局……運命の相手なんて……いなかったのかな？","ENG":"So... There's no such thing as soul mates, is there?","TWN":"結果……命運之人什麼的……是不存在的嗎？"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그래...... 이런 게 내게 어울리는 결말이지.","JPN":"そう……これが私にぴったりの結末。","ENG":"Yes... This is such a fitting end for someone like me.","TWN":"也是……這才是最適合我的結局。"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하긴 악당에게 해피엔딩이라니..... 가당치도 않네.","JPN":"確かに悪党にハッピーエンドなんて……相応しくないか。","ENG":"Villains don't deserve a happy ending. What was I thinking?","TWN":"反派怎麼可能會有幸福結局呢……真是可笑。"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"겨우 찾았다고 생각했는데...... 어째서......","JPN":"やっと見つけたと思ったのに……どうして……","ENG":"I thought I'd finally found him... Why...","TWN":"本來以為終於找到了……為什麼……"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"왜 그렇게 시무룩해져 있나, 누굴 잃기라도 한 것처럼.","JPN":"どうして、そんな暗い顔をしているんだ。大切な人でも失ったのか？","ENG":"Why are you so sullen? You look as if you've lost someone.","TWN":"妳為什麼要這麼難過，好像失去了什麼重要的人一樣。"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"하, 이젠 환청까지 들리는 건가.","JPN":"はぁ、幻聴まで聞こえるなんて。","ENG":"Hah, now I'm even hearing things.","TWN":"唉，連幻聽都出現了。"},"stage":{"bg":"SUMMER_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FIREWORK"},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이쪽일세.","JPN":"こっちだ。","ENG":"I'm here.","TWN":"我在這裡。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"서, 선배님?!","JPN":"せ、先輩！？","ENG":"D-Dark?","TWN":"前、前輩？！"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"무사한 것 같아서 다행이군, 후배님.","JPN":"無事で良かったよ。","ENG":"I'm glad you're safe, Lone.","TWN":"妳沒事真是太好了，後輩。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님? 살아계셨던 건가요? 대체 어떻게?","JPN":"先輩？　生きていたのですか？　いったいどうやって？","ENG":"Dark! You're alive! But how?","TWN":"前輩？你還活著？怎麼會？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"거대 로봇에 설치해둔 탈출 장치가 성능이 너무 좋아서 말이지.","JPN":"巨大ロボットに設置しておいた脱出装置の性能が良くてな。","ENG":"My robot had a powerful ejector.","TWN":"我在巨大機器人裡安裝的逃命裝置性能實在太好了。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아주 멀리까지 날아가는 바람에 돌아오느라 시간이 좀 걸렸다네.","JPN":"遠くに飛ばされてしまい、戻ってくるのに少し時間がかかったのだ。","ENG":"I was sent so far away that it took me a long time to come back.","TWN":"飛得距離比我預想得還要遠，所以回來的時候花了一點時間。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"설마 이 불사신 머신갑 다크님께서 죽었다고 생각한 건 아니겠지?","JPN":"まさか、この不死身のマシーン-甲-ダークが死んだと思ったのか？","ENG":"You didn't think I, the immortal Machine G.A.P. Dark, was dead, did you?","TWN":"妳該不會以為我這不滅的機甲·皇級Type：黑暗大人就這麼死了吧？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그, 그럴리가요......","JPN":"い、いえ！　そんな……","ENG":"O-of course not.","TWN":"怎、怎麼可能……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"흐윽...... 그럴 리가...... 흐그극...... 없잖아요!","JPN":"うぅ……そんなわけ……ひっく……ないじゃないですか！","ENG":"*Sniffle* Absolutely... *Sniffle* Not!","TWN":"嗚……沒有……嗚嗚……真的沒有！"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"역시 날 믿어주는 건 후배님뿐이라니까.","JPN":"やはり私を信じてくれるのは後輩さんだけだ。","ENG":"I knew I could count on you, Lone.","TWN":"果然，就只有後輩會相信我。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그러니까 이제 울지 말게. 씩씩하고 악당답게, 웃으면서 살아가기로 약속하지 않았나?","JPN":"だから、もう泣くな。凜々しく、悪党らしく、笑顔で生きていくと約束してくれないか？","ENG":"Now, stop crying. You promised to me that you'd live happily like the spirited villainess you are.","TWN":"所以別再哭了。妳不是和我約好了，說要像個堅強反派一樣，笑著活下去嗎？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네, 선배님.","JPN":"はい、先輩。","ENG":"Yes, Dark.","TWN":"是的，前輩。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저 웃을게요. 선배님과 같은 악당이니까, 울지 않아요.","JPN":"これからは笑います。先輩と同じ悪党だから、もう泣きません。","ENG":"I'll smile. I'm a villain, just like you. I won't cry anymore.","TWN":"我會笑的，我是和前輩一樣的反派，我不會哭的。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그래, 훨씬 보기 좋군.","JPN":"あぁ、その方がずっといい。","ENG":"Yes, that's much better.","TWN":"沒錯，這樣就好多了。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그보다...... 찾고 있던 건 결국 찾은 건가?","JPN":"それより……探していたものは見つかったのか？","ENG":"So, did you find what you were looking for?","TWN":"對了……妳要找的東西找到了嗎？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Pardon?","TWN":"什麼……？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"자네와 이어진 운명의 상대 말일세. 교도소에서부터 항상 찾고 있지 않았나?","JPN":"君の運命の糸で結ばれた相手だ。刑務所にいた頃からずっと探していたのだろう？","ENG":"Your soul mate. You've been looking for him, even when you were in prison.","TWN":"和妳心心相連的命運之人，妳不是從在監獄裡的時候，就一直在尋找嗎？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"내가 알려준 탐정 사무소가 도움이 되었는지 모르겠군.","JPN":"私が紹介した探偵事務所が役に立ったかどうかは不明だが。","ENG":"I don't know if the private investigator office I recommended to you helped.","TWN":"我為妳推薦的偵探事務所不知道有沒有幫到妳？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저는......","JPN":"私は……","ENG":"I…","TWN":"我……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"음? 왜 내 렌즈만 빤히 쳐다보고 있나?","JPN":"うん？　なぜ私のレンズを見つめているのだ？","ENG":"Mm? Why are you staring at my lenses?","TWN":"嗯？為什麼盯著我的鏡頭看？"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아직 찾지 못했다면 다른 괜찮은 곳을 알선해주도록 하겠네.","JPN":"まだ見つけられていないのなら、他の探偵事務所を紹介しよう。","ENG":"If it wasn't helpful, I can hook you up with different investigators.","TWN":"如果還沒找到，我就推薦另一家給妳。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아뇨.","JPN":"いえ。","ENG":"No.","TWN":"不用了。"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"그러니까......","JPN":"えっと……","ENG":"I mean...","TWN":"因為……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"저......","JPN":"あの……","ENG":"I...","TWN":"我……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"찾은 것 같아요......","JPN":"見つかりました……","ENG":"I think I've found him.","TWN":"好像已經找到了……"},"stage":{"bg":"SUMMER_06","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"하암~ 지루하군. 지루해.","JPN":"ふわぁ～、つまらんのう。実につまらぬ。","ENG":"*Yawn* Boring. So boring!","TWN":"唉～好無聊喔，好無聊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이번 휴가 땐 구경거리도 많고 꽤 즐거웠는데~","JPN":"この前の休暇は実に面白いものを、たくさん見ることができたというのに。","ENG":"I had such a great time out at that resort.","TWN":"這次暑假超有看頭，過得超開心的～"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내년 여름은 대체 언제 돌아오려나.","JPN":"来年の夏はいったいいつになったら訪れるのじゃ。","ENG":"I can't wait for the next summer.","TWN":"明年夏天什麼時候才會來呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"주인님? 지난 번에 여기 저기 올리신 드라마 공모전 결과가 나왔습니다만.","JPN":"ロザリア様？　この前、あちこちに出したドラマコンペの結果が出ました。","ENG":"Mistress, you've got responses for the show script that you submitted.","TWN":"主人？您上次到處投稿的各家電視劇徵稿大賽結果出來了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"오, 그래. 물론 보낸 곳 모두 최고의 찬사를 보내왔겠지? 어느 방송사를 골라야 하려나~","JPN":"うむ。もちろんすべて最高の賛辞を送ってきたのじゃろう？　どのテレビ局を選べば良いか悩みものじゃ。","ENG":"Ooo, that's right! I bet they can't stop singing praises for my writing skills. So, which broadcast network do you think I should go with?","TWN":"哦，是嗎。評審員一定是大加讚賞了吧？我要選哪一家電視臺好呢～"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"1차 심사에서 모두 떨어졌다고 하네요.","JPN":"すべて1次選考で不合格という知らせです。","ENG":"They've all disqualified you in the preliminary screening stage.","TWN":"在初審就全部落選了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"엥? 거짓말! 거짓말!","JPN":"は？　嘘じゃ！　そんなのは嘘じゃ！","ENG":"What? You're lying, aren't you?","TWN":"什麼？騙人！騙人！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이런 흥미진진한 이야기를 또 어디서 찾을 수 있다는 거야?","JPN":"これよりも興味深い話が、他にあるというのか！？","ENG":"They couldn't find such an interesting story anywhere else!","TWN":"我這熱血激昂的故事在哪裡才找得到啊？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"게다가 실화를 바탕으로 쓴 거잖아! 필멸자들은 이런 걸 좋아하는 줄 알았는데?","JPN":"実話を基に書いたのじゃぞ？　虫けらどもはこういうものを好むと思ったのじゃが……","ENG":"It's based on a real story, too! I thought mortals liked this sort of thing.","TWN":"而且還是根據真人真事寫的耶，必滅者不是最喜歡這樣的劇情嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"아무래도 인간들이 납득할 수 있는 현실성의 범주를 벗어난 것 같습니다만.","JPN":"どうやら、人間たちが納得できる現実性の範疇を超えてしまったようです。","ENG":"It's probably out of comprehensible range for them.","TWN":"看來是劇本超出了人類在現實中所能接受的範圍。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"뭐, 그래도 제 각본은 입상을 했으니 당분간 예산 걱정은 덜겠네요.","JPN":"まぁ、でも私の脚本は入賞したので、しばらくは予算の心配は要りませんね。","ENG":"Well, at least mine won a prize. That should help with our budget for a while.","TWN":"但好在我的劇本順利得了獎，所以暫時不用擔心預算問題。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이 몸이 떨어졌는데 누가 입상을 했다고? 그런 거 인정 못해!","JPN":"妾が落ちたというのに、誰が入賞しただと？　そんなこと認められぬ！","ENG":"I was disqualified, and you won? That's completely unacceptable!","TWN":"連我都落選了，居然還有人得獎？豈有此理！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그 따위 심사를 한 엉터리 전문가들을 내 앞에 끌고 오거라! 당장! 당자앙!","JPN":"そのような審査を行ったインチキ専門家どもを、妾の前に連れて来るのじゃ！　今すぐ！","ENG":"Bring me those phony experts who had the nerve to disqualify me! RIGHT NOWWWW!","TWN":"把那些笨蛋評審都給我帶過來！立刻！立～刻！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                  HAPPY-END","JPN":"                                                                                  HAPPY-END","ENG":"                                                                                  Happy Ending","TWN":"                                                                                  HAPPY-END"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                  HAPPY-END?","JPN":"                                                                                  HAPPY-END?","ENG":"                                                                                  Happy Ending?","TWN":"                                                                                  HAPPY-END？"},"stage":{"bg":"SUMMER_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_02"}]`);export{e as default};